// Filter out items with no id or empty id
const filteredItems = items.filter(item => item.json.id !== undefined && item.json.id !== null);

// Extract all IDs
const ids = filteredItems.map(item => item.json.id);

// Create a Set to ensure uniqueness
const uniqueIds = new Set(ids);

// Return the count
return [{
  json: {
    distinctIdCount: uniqueIds.size
  }
}];

// Pass forward both JSON data and binary
return items.map(item => {
  return {
    json: {
      originalData: item.json, // save form fields
    },
    binary: item.binary, // keep the binary file here
  };
});

